using UnityEngine;

public class GrindableSurface : MonoBehaviour
{
    [Header("Grind Path")]
    public Transform startPoint; // Where the player will be positioned when starting the grind
    public Transform endPoint; // The end of the grind

    [Header("Surface Properties")]
    public float grindingSpeed = 5f; // The speed at which the player will move along the grind
    public Vector3 direction; // Direction calculated from the start to the end point

    [Header("Grinding Events")]
    public UnityEngine.Events.UnityEvent OnGrindStart;
    public UnityEngine.Events.UnityEvent OnGrindEnd;

    private bool isGrinding = false;

    void Awake()
    {
        if (startPoint != null && endPoint != null)
        {
            // Direction from start to end normalized
            direction = (endPoint.position - startPoint.position).normalized;
        }
    }

    void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Player") && !isGrinding)
        {
            StartGrind();
        }
    }

    void OnTriggerExit(Collider other)
    {
        if (other.CompareTag("Player") && isGrinding)
        {
            StopGrind();
        }
    }

    void StartGrind()
    {
        isGrinding = true;
        OnGrindStart.Invoke();
    }

    void StopGrind()
    {
        isGrinding = false;
        OnGrindEnd.Invoke();
    }

    public Vector3 GetDirection()
    {
        return direction;
    }

    public float GetSpeed()
    {
        return grindingSpeed;
    }
}

